		public static Infrastructure.Data.Entities.Joins.Logistics.PSZ_Eingangskontrolle_TNEntity GetPalntBookingsMinMaxByLagerID(int LagerID, int order)
		{
			var dataTable = new DataTable();
			

			using(var sqlConnection = new SqlConnection(Settings.ConnectionString))
			{
				sqlConnection.Open();
				string query = "";
				if(order == 1)//Max
				{
					query = @"SELECT TOP 1
							*
							FROM [PSZ_Eingangskontrolle_TN]
							WHERE LagerortID = @LagerID
							ORDER BY [Nummer Verpackung] DESC";
				}
				else if(order == 2)
				{
					query = @"SELECT TOP 1
							*
							FROM [PSZ_Eingangskontrolle_TN]
							WHERE LagerortID = @LagerID
							ORDER BY [Nummer Verpackung]";
				}
				var sqlCommand = new SqlCommand(query, sqlConnection);

				sqlCommand.Parameters.AddWithValue("LagerID", LagerID);
				DbExecution.Fill(sqlCommand, dataTable);
