		public static decimal GetAnzahlNach(int LagerId, int WereingangId,int ID)
		{
			var dataTable = new DataTable();

			using(var sqlConnection = new SqlConnection(Infrastructure.Data.Access.Settings.ConnectionString))
			{
				sqlConnection.Open();

				string query = @"SELECT SUM(l.Anzahl_nach) AS Anzahl_nach FROM Bestellungen B
					INNER JOIN [bestellte Artikel] BA ON BA.[Bestellung-Nr] = B.Nr
					INNER JOIN Artikel A ON A.[Artikel-Nr] = BA.[Artikel-Nr]
					INNER JOIN Bestellnummern BE ON B.[Lieferanten-Nr] = BE.[Lieferanten-Nr]
					INNER JOIN Lagerbewegungen_Artikel l ON l.WereingangId = BA.Nr
					AND A.[Artikel-Nr] = BE.[Artikel-Nr]   
					AND l.WereingangId = @WereingangId
					AND l.lager_nach = @LagerId
					GROUP BY  l.[WereingangId] , l.ID 
					Having l.ID=@ID";

				var sqlCommand = new SqlCommand(query, sqlConnection);
				sqlCommand.Parameters.AddWithValue("LagerId", LagerId);
				sqlCommand.Parameters.AddWithValue("WereingangId", WereingangId);
				sqlCommand.Parameters.AddWithValue("ID", ID);

				DbExecution.Fill(sqlCommand, dataTable);
			}

			if(dataTable.Rows.Count > 0)
			{
				return (dataTable.Rows[0]["Anzahl_nach"] == System.DBNull.Value) ? 0 : Convert.ToDecimal(dataTable.Rows[0]["Anzahl_nach"]);
			}
			else
			{
				return 0;
			}
		}
